- (BOOL)jun_routeRequestDismissWhenTransitionToViewController:(UIViewController *)vc url:(NSURL *)url cursor:(int)cursor {
    if ([vc isKindOfClass:[WBLoginViewController class]]) return false;
    return true;
}

- (instancetype)initWithSource:(NSString *)source triggerId:(nullable NSString *)triggerId {
    if (self = [super init]) {
        self.source = source;
        self.paymentInquiryFailedCount = 0;
        self.couponCode = nil;
        self.allProducts = WBPaymentManager.sharedManager.goods;

        if ([triggerId isKindOfClass:NSMutableString.class]) {
            self.triggerId = [triggerId copy]; // 安全复制
        } else {
            self.triggerId = triggerId;
        }
    }
    return self;
}

- (void)viewDidLoad {
    [super viewDidLoad];
    self.title = @"会员中心";
    UIImage *returnImage = [[[UIImage wb_imageNamed:@"返回1"] imageByResizeToSize:CGSizeMake(WBRpt(24), WBRpt(24)) contentMode:UIViewContentModeScaleAspectFit] imageWithRenderingMode:UIImageRenderingModeAlwaysOriginal];
    self.navigationItem.leftBarButtonItem = [[UIBarButtonItem alloc] initWithImage:returnImage style:UIBarButtonItemStylePlain target:self action:@selector(returnButtonClicked)];
    self.view.backgroundColor = RGB(248, 248, 248);
    [self addAllSubviews];
    [self addAllConstraints];
    [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(accountStatusChanged) name:WBAccountStatusChangedNotification object:nil];
    [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(afterSelectPayMethod) name:WBSelectPayMethodNotification object:nil];
    [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(handleNormalReturnAndDismissAction) name:WBRouteCloseVIPNotification object:nil];
    [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(loadPromos) name:WBVipReloadPromoNotification object:nil];
    [self refreshData];
    self.features = [WBVIPFeatureManager.sharedManager getFeatures];
    if (self.currentProducts.count > 0) {
        [self.payOptionsView updateWithServerPayMethods:[self getSelectedProductModel].serverPayMethods];
    }
    WBPaymentManager.sharedManager.observer = self;
    _headerView.delegate = self;
    _productCollectionView.productDelegate = self;
}

- (void)didSelectProductModel:(WBProductModel *)productModel {
    self.selectedProductModel = productModel;
    [self updatePromoAndPurchaseView:productModel];
}

// 点击“登录/注册”按钮
- (void)headerViewDidClickLoginButton {
    if (kStringIsEmpty(WBSettingManager.sharedManager.Mobile)) {
        WBLoginViewController *loginVC = [[WBLoginViewController alloc] init];
        WBNavigationController *navVC = [[WBNavigationController alloc] initWithRootViewController:loginVC];
        navVC.modalPresentationStyle = UIModalPresentationFullScreen;   // 全屏

        [self presentViewController:navVC animated:YES completion:nil]; // 模态视图展示
    }
}

- (void)viewWillAppear:(BOOL)animated {
    [super viewWillAppear:animated];
    self.inFront = TRUE;
    [WBRouteActionManager sharedManager].isPayingNoAds = TRUE;
}

- (void)viewDidAppear:(BOOL)animated {
    [super viewDidAppear:animated];
    if (self.currentProducts.count > 0) {
        [self loadPromos];
    }
    [self.headerView setNeedsRefreshUI];
    if (!self.actionRequestVipPresentOnceToken) {
        NSMutableDictionary *data = [NSMutableDictionary dictionary];
        data[@"source"] = self.source;
        if (self.triggerId) {
            data[@"triggerId"] = self.triggerId;
        }
        [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypePageVipPresented data:data defaultHandler:nil];
        self.actionRequestVipPresentOnceToken = true;
    }
}

- (void)viewWillDisappear:(BOOL)animated {
    [super viewWillDisappear:animated];
    self.inFront = FALSE;
    [WBRouteActionManager sharedManager].isPayingNoAds = FALSE;
}

- (void)dealloc {
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

