@implementation WBRouteActionManager

+ (instancetype)sharedManager {
    static id manager = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        manager = [[self alloc] init];
    });
    return manager;
}

- (instancetype)init {
    self = [super init];
    if (self) {
        self.originVC = nil;
        self.observerTokens = [NSMutableArray array];

        // 添加对 "常规弹窗关闭" 观察者
        [self.observerTokens addObject:[[NSNotificationCenter defaultCenter] addObserverForName:WBPopupDismissNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(POPUP_DELAY * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                [self handlePopupDismissal];
            });
        }]];

        // 添加对 "静态弹窗关闭" 观察者（图片弹窗）
        [self.observerTokens addObject:[[NSNotificationCenter defaultCenter] addObserverForName:CustomPopupDismissedNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(POPUP_DELAY * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                [self handlePopupDismissal];
            });
        }]];

        // 添加对 "动态弹窗关闭" 观察者（动画弹窗）
        [self.observerTokens addObject:[[NSNotificationCenter defaultCenter] addObserverForName:DynamicPopupDismissedNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(POPUP_DELAY * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                [self handlePopupDismissal];
            });
        }]];

        // 添加对 "静态弹窗领取优惠券" 和 "动态弹窗领取优惠券" 观察者
        [self.observerTokens addObject:[[NSNotificationCenter defaultCenter] addObserverForName:WBStaticPromoReceiveNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            self.whichTogetPromo = @"static";
        }]];

        [self.observerTokens addObject:[[NSNotificationCenter defaultCenter] addObserverForName:WBDynamicPromoReceiveNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            self.whichTogetPromo = @"dynamic";
        }]];

        // 添加对 "会员中心关闭" 的观察者
        [self.observerTokens addObject:[[NSNotificationCenter defaultCenter] addObserverForName:WBVipReturnNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(POPUP_DELAY * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                [self handlePopupQueueLeft];
            });
        }]];

        // 添加对 "登录/注册界面关闭" 的观察者
        [self.observerTokens addObject:[[NSNotificationCenter defaultCenter] addObserverForName:WBLoginReturnNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(POPUP_DELAY * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                [self handlePopupQueueLeft];
            });
        }]];

        // 添加对 "优惠券界面关闭" 的观察者
        [self.observerTokens addObject:[[NSNotificationCenter defaultCenter] addObserverForName:WBPromoReturnNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(POPUP_DELAY * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                [self handlePopupQueueLeft];
            });
        }]];
    }
    return self;
}

- (void)dealloc {
    // 移除观察者
    if (self.observerTokens) {
        for (id observerToken in self.observerTokens) {
            [[NSNotificationCenter defaultCenter] removeObserver:observerToken];
        }
        self.observerTokens = nil;
    }
}

- (void)storePopupDataForLater:(NSDictionary *)richMessagesData {
    // 将 richMessagesData 暂时存储到 self.storePopupData 中
    @synchronized (self) {
        self.storePopupData = richMessagesData;
    }
}

- (void)handleSplashAdClose {
    if (self.storePopupData) {
        @synchronized (self) {
            WBPopupShowStatus status = [[WBPopupDecisionMaker sharedInstance] shouldShowPopup];
            if (status == WBPopupShowStatusShow) {
                [self handleRichMessages:self.storePopupData];  // 展示暂存的弹窗数据
                self.storePopupData = nil;
            }
        }
    }
}

- (void)showPopupForStyle:(NSNumber *)style withUserInfo:(NSDictionary *)popupInfo {
    if ([style intValue] == 0 || [style intValue] == 1) {
        WBNoticeModel *richMes = [[WBNoticeModel alloc] initWithDict:popupInfo sourceInterface:self.sourceInterface];
        WBPopupManager *popupManager = [WBPopupManager sharedManager];
        if (self.stashedDefaultHandler) {
            popupManager.stashedDefaultHandler = self.stashedDefaultHandler;
            self.stashedDefaultHandler = nil;
        }
        [popupManager initPopups:@[richMes]];
        [popupManager showPopup];
        [popupManager setStashedDefaultHandler:nil]; // 清理可能的循环引用
    } else if ([style intValue] == 2) {
        NSString *resourceUrlString = popupInfo[@"rich_message"][@"image"];
        if ([resourceUrlString hasSuffix:@".zip"]) {    // 如果资源是压缩包
            WBDynamicPopupResUnzip *dynamicPopManager = [WBDynamicPopupResUnzip sharedManager];
            [dynamicPopManager presentPopupWithZipUrl:resourceUrlString popupInfo:popupInfo];
        } else if([resourceUrlString hasSuffix:@".png"] ||
                  [resourceUrlString hasSuffix:@".jpg"] ||
                  [resourceUrlString hasSuffix:@".jpeg"] ||
                  [resourceUrlString hasSuffix:@".webp"]) {    // 如果资源是图片
            WBCustomPopupManager *customPopupManager = [WBCustomPopupManager sharedManager];
            if (self.stashedDefaultHandler) {
                customPopupManager.stashedDefaultHandler = self.stashedDefaultHandler;
                self.stashedDefaultHandler = nil;
            }
            [customPopupManager showCustomPopupWithUserInfo:popupInfo];
            [customPopupManager setStashedDefaultHandler:nil]; // 清理可能的循环引用
        } else {    // 如果 image字段为空
            WBDynamicPopupResUnzip *dynamicPopManager = [WBDynamicPopupResUnzip sharedManager];
            [dynamicPopManager loadResourcesFromUnzippedArchive:@"" popupInfo:popupInfo];
        }
    }
}

- (void)showNextPopupFromQueue:(NSMutableArray<NSDictionary *> *)popupQueue {
    if (self.popupQueue.count > 0) {
        NSDictionary *popupInfo = popupQueue.firstObject;
        NSNumber *style = popupInfo[@"rich_message"][@"style"];
        [self showPopupForStyle:style withUserInfo:popupInfo];
    }
}

- (void)handlePopupQueueLeft {
    if ([self.popupQueueLeft count] > 0) {
        [self showNextPopupFromQueue:self.popupQueueLeft];
        [self.popupQueueLeft removeObjectAtIndex:0];
    }
}

- (void)handlePopupDismissal {
    UIViewController *currentVC = [WBAppManager getUIApplicationCurrentViewController];

    if ([self.popupQueue count] > 0) {
        [self.popupQueue removeObjectAtIndex:0];
        if ([self.popupQueue count] > 0) {
            if ([currentVC isEqual:self.originVC]) {
                [self showNextPopupFromQueue:self.popupQueue];
            } else {
                self.popupQueueLeft = self.popupQueue;
                self.popupQueue = nil;
            }
        }
    }
}

- (void)handleRichMessages:(NSDictionary *)richMessagesData {
    id richMessagesObject = nil; // 初始化 richMessagesObject

    if (richMessagesData[@"rich_message"]) {    // 如果里面是rich_message
        richMessagesObject = richMessagesData[@"rich_message"];
