+#pragma mark - 处理ProductIdList
+
+// 将 ProductIdList 转换为 NSNumber 数组
+- (NSArray<NSNumber *> *)handleProductIdList:(NSString *)input {
+    if (input.length == 0) {
+        NSLog(@"productIdList为空");
+        return nil;
+    }
+    NSMutableArray<NSNumber *> *productIDs = [NSMutableArray array];
+    NSCharacterSet *whitespaceSet = [NSCharacterSet whitespaceCharacterSet];
+    
+    // 去空格 + 数字校验
+    [[input componentsSeparatedByString:@","] enumerateObjectsUsingBlock:^(NSString *str, NSUInteger idx, BOOL *stop) {
+        NSString *trimmedStr = [str stringByTrimmingCharactersInSet:whitespaceSet];
+        if (trimmedStr.length == 0) return;
+
+        NSScanner *scanner = [NSScanner scannerWithString:trimmedStr];
+        NSInteger value;
+        if ([scanner scanInteger:&value] && scanner.isAtEnd) {
+            [productIDs addObject:@(value)];
+        }
+    }];
+    
+    return (productIDs.count > 0) ? [productIDs copy] : nil;
+}
